@ARTICLE{10.2196/15895,
	author = {Ector GI and Westerweel PE and Hermens RP and Braspenning KA and Heeren BC and Vinck OM, de Jong JJ and Janssen JJ and Blijlevens NM},
	title = {The Development of a Web-Based, Patient-Centered Intervention for Patients With Chronic Myeloid Leukemia (CMyLife): Design Thinking Development Approach.},
	journal = {J Med Internet Res},
	year = {2020},
	abstract = {BACKGROUND: With the global rise in chronic health conditions, health care is transforming, and patient empowerment is being emphasized to improve treatment outcomes and reduce health care costs. Patient-centered innovations are needed. We focused on patients with chronic myeloid leukemia (CML), a chronic disease with a generally good long-term prognosis because of the advent of tyrosine kinase inhibitors. However, both medication adherence by patients and guideline adherence by physicians are suboptimal, unnecessarily jeopardizing treatment outcomes. OBJECTIVE: The aim of this study was to develop a patient-centered innovation for patients with CML using a design thinking methodology. METHODS: The 5 phases of design thinking (ie, empathize, define, ideate, prototype, and test) were completed, and each phase started with the patient. Stakeholders and end users were identified and interviewed, and observations in the care system were made. Using tools in human-centered design, problems were defined and various prototypes of solutions were generated. These were evaluated by patients and stakeholders and then further refined. RESULTS: The patients desired (1) insights into their own disease; (2) insights into the symptoms experienced, both in terms of knowledge and comprehension; and (3) improvements in the organization of care delivery. A web-based platform, CMyLife, was developed and pilot-tested. It has multiple features, all targeting parts of the bigger solution, including a website with reliable information and a forum, a guideline app, personal medical records with logs of symptoms and laboratory results (including a molecular marker and linked to the guideline app), tailored feedback based on the patients' symptoms and/or results, screen-to-screen consulting, delivery of medication, and the collection of blood samples at home. CONCLUSIONS: The multifeatured innovation, CMyLife, was developed in a multidisciplinary way and with active patient participation. The aim of developing CMyLife was to give patients the tools to monitor their results, interpret these results, and act on them. With this tool, they are provided with the know-how to consider their results in relation to their personal care process. Whether CMyLife achieves its goal and the evaluation of the added value will be the focus of future studies. CML could become the first malignancy for which patients are able to monitor and manage their disease by themselves.},
	doi = {10.2196/15895},
	pmid = {32412424 [Indexed for MEDLINE]},
	note = {PMC7260663}
}

@ARTICLE{10.2196/17018,
	author = {Arts LPJ and Oerlemans S and Posthuma EFM and Issa DE and Oosterveld M, van der Griend R and Nijziel MR, van de Poll-Franse LV},
	title = {Web-Based Self-Management for Patients With Lymphoma: Assessment of the Reach of Intervention of a Randomized Controlled Trial.},
	journal = {J Med Internet Res},
	year = {2020},
	abstract = {BACKGROUND: Randomized controlled trials (RCTs) often provide accurate estimates of the internal validity of an intervention but lack information on external validity (generalizability). We conducted an RCT on the effectiveness of a self-management intervention among patients with lymphoma in a population-based setting. OBJECTIVE: The objectives of the current study were to describe the proportion of RCT participants compared to all patients invited to participate, and compare sociodemographic and clinical characteristics of RCT participants with all respondents, all patients invited to participate, and all patients selected from the Netherlands Cancer Registry (NCR) to determine the reach of the intervention. An additional objective was to assess differences on RCT outcome variables between RCT and paper respondents. METHODS: Patients with lymphoma or chronic lymphocytic leukemia ≥18 years old at diagnosis from 13 hospitals in the Netherlands were selected from the population-based NCR, which routinely collects data on sociodemographic and clinical characteristics. Eligible patients were invited to participate in an RCT and complete a questionnaire. Web-based completion determined RCT enrollment, whereas paper respondents were followed observationally. RESULTS: A total of 1193 patients were selected from the NCR, 892 (74.77%) of whom were invited to participate in the trial by their hematologist after verifying eligibility. Among those invited, 25.4% (227/892) completed the web-based questionnaire and were enrolled in the RCT. The RCT participants were younger and there was a higher proportion of men than nonparticipants (P<.001). In addition, 25.7% (229/892) of those invited opted to participate in the paper-based observational follow-up study. Compared with paper respondents, RCT participants were younger (P<.001), with a higher proportion of men (P=.002), and had higher education levels (P=.02). RCT participants more often wanted to receive all available information on their disease (P<.001), whereas paper respondents reported higher levels of emotional distress (P=.009). CONCLUSIONS: From a population-based sample of eligible patients, the participation rate in the RCT was approximately 25%. RCT participants may not be representative of the target population because of different sociodemographic and clinical characteristics. Since RCT participants represent a minority of the target population, RCT results should be interpreted with caution as patients in the RCT may be those least in need of a self-management intervention. TRIAL REGISTRATION: Netherlands Trial Register NTR5953; https://www.trialregister.nl/trial/5790.},
	doi = {10.2196/17018},
	pmid = {32406858 [Indexed for MEDLINE]},
	note = {PMC7256744}
}

@ARTICLE{10.1182/blood.2019003116,
	author = {Geyer HL and Gazelka H and Mesa R},
	title = {How I treat pain in hematologic malignancies safely with opioid therapy.},
	journal = {Blood},
	year = {2020},
	abstract = {The field of malignant hematology has experienced extraordinary advancements with survival rates doubling for many disorders. As a result, many life-threatening conditions have since evolved into chronic medical ailments. Paralleling these advancements have been increasing rates of complex hematologic pain syndromes, present in up to 60% of patients with malignancy who are receiving active treatment and up to 33% of patients during survivorship. Opioids remain the practice cornerstone to managing malignancy-associated pain. Prevention and management of opioid-related complications have received significant national attention over the past decade, and emerging data suggest that patients with cancer are at equal if not higher risk of opioid-related complications when compared with patients without malignancy. Numerous tools and procedural practice guides are available to help facilitate safe prescribing. The recent development of cancer-specific resources directing algorithmic use of validated pain screening tools, prescription drug monitoring programs, urine drug screens, opioid use disorder risk screening instruments, and controlled substance agreements have further strengthened the framework for safe prescribing. This article, which integrates federal and organizational guidelines with known risk factors for cancer patients, offers a case-based discussion for reviewing safe opioid prescribing practices in the hematology setting.},
	doi = {10.1182/blood.2019003116},
	pmid = {32352512 [Indexed for MEDLINE]},
	note = {PMC8765122}
}

@ARTICLE{10.2217/fon-2019-0555,
	author = {Gambacorti-Passerini C, le Coutre P and Piazza R},
	title = {The role of bosutinib in the treatment of chronic myeloid leukemia.},
	journal = {Future Oncol},
	year = {2020},
	abstract = {The availability of several BCR-ABL1 tyrosine kinase inhibitor (TKI) options means physicians and patients can select the most appropriate treatment for a patient with chronic myeloid leukemia (CML). BCR-ABL TKI selection as a first- or later-line therapy is dependent on a number of clinical factors. Regular monitoring of patients, patient education, dose optimization and management of treatment-emergent adverse events are key aspects of long-term chronic myeloid leukemia management and contribute to improved clinical outcomes, quality of life, patient adherence and healthcare costs. This review provides an overview of the BCR-ABL1 TKI bosutinib, its pharmacology and clinical trials; discusses the impact of comorbidities and concomitant medications on bosutinib treatment selection; and suggests strategies for managing adverse events and dose optimization during bosutinib treatment.},
	doi = {10.2217/fon-2019-0555},
	pmid = {31833784 [Indexed for MEDLINE]}
}

@ARTICLE{10.1089/jayao.2019.0063,
	author = {Saita E and Acquati C},
	title = {Evaluating the Framed Portrait Experience as an Intervention to Enhance Self-Efficacy and Self-Esteem in a Sample of Adolescent and Young Adult Cancer Survivors: Results of a Pilot Study.},
	journal = {J Adolesc Young Adult Oncol},
	year = {2020},
	abstract = {Cancer diagnosis and treatments negatively affect quality of life and developmental processes of adolescents and young adults (AYAs), with self-esteem, self-efficacy, and body image discomfort reported. Despite increasing awareness of the psychosocial issues experienced by this group, a paucity of psychosocial interventions has been developed. This study aims to investigate the Framed Portrait Experience (FPE) as an intervention to promote well-being among AYA cancer survivors. A pilot study was conducted using a quasi-experimental design. The sample included 18 AYA leukemia survivors. Individuals in the intervention group (n = 10) participated in the FPE, a psychosocial program consisting of two sessions. In the first one, starting from the illness narrative recollected by the individual, pictures representing the subject in meaningful contexts are taken. Then, a selected number of pictures are used in a second encounter with a therapist to integrate the disease within past, present, and future of the participant. Survivors in the comparison group (n = 8) were offered usual psychosocial care at the participating institute. Measures of personality traits, coping, self-efficacy, self-esteem, and body image were compared at pre-test and 3 months later. Significant differences in self-efficacy and self-esteem scores were identified at post-test between the intervention and comparison group (p < 0.05). No significant differences were identified for body self-esteem. These findings provide initial evidence supporting the FPE as a low-cost and easy-to-implement intervention to promote self-efficacy and self-esteem among AYA survivors. Further research with larger samples, with more rigorous designs, and different cancer types is needed.},
	doi = {10.1089/jayao.2019.0063},
	pmid = {31742467 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ejon.2019.07.006,
	author = {White LL and Kupzyk KA and Berger AM and Cohen MZ and Bierman PJ},
	title = {Self-efficacy for symptom management in the acute phase of hematopoietic stem cell transplant: A pilot study.},
	journal = {Eur J Oncol Nurs},
	year = {2019},
	abstract = {PURPOSE: Hematopoietic stem cell transplant (HSCT) is an intensive treatment associated with distressing treatment and disease-related symptoms that affect patient outcomes such as functional status and quality of life. Self-efficacy for symptom management (SESM) is a person's belief in their ability to perform behaviors to prevent and relieve symptoms. Presence of SESM can impact symptom distress and functional status. This study describes the changes over time and relationships among SESM, symptom distress, and physical functional status in adults during the acute phase of HSCT. METHODS: Patients (n = 40) completed measures of symptom distress, SESM, and physical function at time points prior to and at days 7, 15 and 30 post-transplant. Clinical outcomes were length of stay and number of readmissions. RESULTS: Symptom distress, physical function, and SESM changed significantly over time. There was a significant negative relationship between symptom distress and physical function and between symptom distress and SESM at all points. The lowest levels of SESM and physical function were at day 7 when symptom distress was highest. Symptom distress was a moderator for the relationship between physical function and SESM at day 15. CONCLUSION: This was the first study to examine SESM in the acute phase of HSCT. Higher SESM was associated with fewer symptoms and increased physical function. Less symptom distress was associated with higher physical function and confidence to manage symptoms. These findings provide the basis for development of patient-centered interventions to enhance SESM when symptoms are at their highest immediately after HSCT.},
	doi = {10.1016/j.ejon.2019.07.006},
	pmid = {31446260 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/jncimonographs/lgz012,
	author = {Carrozzo M and Eriksen JG and Bensadoun RJ and Boers-Doets CB and Lalla RV and Peterson DE},
	title = {Oral Mucosal Injury Caused by Targeted Cancer Therapies.},
	journal = {J Natl Cancer Inst Monogr},
	year = {2019},
	abstract = {Targeted cancer therapies have fundamentally transformed the treatment of many types of cancers over the past decade, including breast, colorectal, lung, and pancreatic cancers, as well as lymphoma, leukemia, and multiple myeloma. The unique mechanisms of action of these agents have resulted in many patients experiencing enhanced tumor response together with a reduced adverse event profile as well. Toxicities do continue to occur, however, and in selected cases can be clinically challenging to manage. Of particular importance in the context of this monograph is that the pathobiology for oral mucosal lesions caused by targeted cancer therapies has only been preliminarily investigated. There is distinct need for novel basic, translational, and clinical research strategies to enhance design of preventive and therapeutic approaches for patients at risk for development of these lesions. The research modeling can be conceptually enhanced by extrapolating "lessons learned" from selected oral mucosal conditions in patients without cancer as well. This approach may permit determination of the extent to which pathobiology and clinical management are either similar to or uniquely distinct from oral mucosal lesions caused by targeted cancer therapies. Modeling associated with oral mucosal disease in non-oncology patients is thus presented in this context as well. This article addresses this emerging paradigm, with emphasis on current mechanistic modeling and clinical treatment. This approach is in turn designed to foster delineation of new research strategies, with the goal of enhancing cancer patient treatment in the future.},
	doi = {10.1093/jncimonographs/lgz012},
	pmid = {31425602 [Indexed for MEDLINE]}
}

@ARTICLE{10.1177/1078155219864640,
	author = {Reff MJ and Shillingburg A and Shah B and Elder C and Prescott H and Kennerly-Shah J},
	title = {Front-line use of tyrosine kinase inhibitors in chronic phase chronic myeloid leukemia: Practice considerations.},
	journal = {J Oncol Pharm Pract},
	year = {2020},
	abstract = {The development of BCR-ABL-targeting tyrosine kinase inhibitors has transformed chronic phase chronic myeloid leukemia (CP CML) from a disease with a terminal prognosis to a treatable chronic illness. Long-term treatment with tyrosine kinase inhibitors means that patients have to be clinically managed and monitored over extended periods of time, thus a patient-centered, medically integrated, and multidisciplinary oncology healthcare team is required to support patients through their journey. Pharmacists work with patients, physicians, and the wider support team to select the optimum therapy plan for a given patient. These decisions are based on risk factors, comorbidities, concomitant medications, and personal circumstances and pharmacists advise on the efficacy and safety of different treatment options. Additionally, pharmacists are a key point-of-contact and resource for monitoring patient response to treatment, identifying and managing adverse events and drug-drug interactions, any subsequent therapy plan modifications, and, potentially, treatment-free remission. Pharmacists also assist with patient education, medication adherence, and financial discussions with patients throughout the long course of the disease. This review provides an overview of BCR-ABL tyrosine kinase inhibitors, discusses the role of the medically integrated pharmacy team, and suggests strategies that pharmacists can use in patient management and clinical decision-making to optimize the treatment of CP CML.},
	doi = {10.1177/1078155219864640},
	pmid = {31354102 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s13187-019-01574-7,
	author = {Berg CJ and Vanderpool RC and Getachew B and Payne JB and Johnson MF and Sandridge Y and Bierhoff J and Le L and Johnson R and Weber A and Patterson A and Dorvil S and Mertens A},
	title = {A Hope-Based Intervention to Address Disrupted Goal Pursuits and Quality of Life Among Young Adult Cancer Survivors.},
	journal = {J Cancer Educ},
	year = {2020},
	abstract = {Over 70,000 US young adults are diagnosed with cancer annually, disrupting important life transitions and goal pursuits. Hope is a positive psychology construct associated with better quality of life (QOL) that focuses on goal-oriented thinking. We developed and tested Achieving Wellness After Kancer in Early life (AWAKE), a scalable 8-week app-based program consisting of educational videos, mood/activity tracking, and telephone-based coaching to promote hope and QOL in young adult cancer survivors (YACS, 18-40 years old). A two-arm RCT was used to examine the feasibility, acceptability, and potential efficacy of AWAKE (n = 38) versus attention control (AC; n = 18) among YACS within 2 years of completing treatment and recruited from two NCI-designated cancer centers. Outcomes including hope (Trait Hope Scale), QOL (36-Item Short Form Health Survey; Functional Assessment of Cancer Therapy-General), depressive symptoms (Patient Health Questionnaire-9), and substance use were assessed at baseline, 8 weeks, and 6 months. Participants were an average of 32.55 (SD = 5.45) years old; 75.0% were female, and 80.4% White. The most common cancers were breast cancer (28.6%), melanoma (16.1%), and leukemia/lymphoma (12.5%). High retention, engagement, and satisfaction rates were documented in both conditions; AWAKE versus AC participants rated video content as more relevant (p = 0.007) and reported greater likelihood of talking positively about the program (p = 0.005). Many efficacy change scores showed positive trends in AWAKE versus AC. Reorienting to one's goal pursuits after cancer diagnosis and treatment is critical and may be supported through hope-based interventions. Findings suggest that the AWAKE warrants subsequent research testing its efficacy, effectiveness, and scalability.},
	doi = {10.1007/s13187-019-01574-7},
	pmid = {31297743 [Indexed for MEDLINE]},
	note = {PMC6954353}
}

@ARTICLE{10.1016/j.critrevonc.2019.05.013,
	author = {Santini V and Ossenkoppele GJ},
	title = {Hypomethylating agents in the treatment of acute myeloid leukemia: A guide to optimal use.},
	journal = {Crit Rev Oncol Hematol},
	year = {2019},
	abstract = {The hypomethylating agents (HMAs), decitabine and azacitidine, are valuable treatment options in acute myeloid leukemia patients who are not eligible for intensive chemotherapy. Both agents are generally well tolerated, and complications most commonly relate to myelosuppression. Antibiotic / antifungal use, regular monitoring, and proactive patient education are important to minimize these events, and reduce the need for dose delay. Responses to HMAs are often not evident for up to 6 cycles, and there is currently no validated clinical marker for predicting response. Hence, treatment should be continued for at least 4-6 cycles to ensure that patients have sufficient opportunity to respond. Delivery of insufficient numbers of cycles is a key reason for HMA failure, and premature discontinuation must be avoided. Genetic factors offer potential for better predicting responders to HMAs in future, but require further study.},
	doi = {10.1016/j.critrevonc.2019.05.013},
	pmid = {31153036 [Indexed for MEDLINE]}
}
